SELECT votes
FROM voting_data
WHERE location_id = 0 AND precinct_id = 1 AND candidate_id = 0;

SELECT location_name, city, state, contact_phone
FROM locations
WHERE location_id IN (
    SELECT DISTINCT location_id 
    FROM voting_data
);

SELECT COUNT(*) 
FROM voting_data 
WHERE voting_status = 'confirmed' AND voting_date = '2023-04-05';

SELECT location_name
FROM locations
WHERE location_id IN (
  SELECT DISTINCT location_id
  FROM precincts
);
